/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // Preallocate auxiliary vector once.
    std::vector<double> z(n, 0.0);

    y[0] = -r[0];
    double beta = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // First inner loop: compute convolution sum.
        double sum = 0.0;
        #pragma omp parallel for reduction(+:sum) schedule(static)
        for (int i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        alpha = -(r[k] + sum) / beta;

        // Second inner loop: compute new y values via z.
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < k; ++i) {
            z[i] = y[i] + alpha * y[k - i - 1];
        }

        // Copy z back to y.
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < k; ++i) {
            y[i] = z[i];
        }

        y[k] = alpha;
    }
}
