        #pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            q[i] = 0.0;
            double ri = r[i];
            for (int j = 0; j < m; ++j) {
                double aij = A[i][j];
                local_s[j] += ri * aij;
                q[i] += aij + p[j];
