void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Traverse rows of L (trapezoidal lower‑triangular matrix)
    for (int i = 0; i < n; ++i) {
        // Load the i‑th row of L only once
        const double* Li = L[i].data();          // Pointers to raw data
        double   sum = b[i];                     // x[i] = b[i] initially

        // Apply forward substitution on previous elements
        // The inner loop has no loop‑carried dependency, so compiler
        // can auto‑vectorise it
        #pragma omp simd
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * x[j];
        }

        // Store the computed value of x[i]
        x[i] = sum / Li[i];
    }
}
