/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                const std::vector<double>& y_1,
                const std::vector<double>& y_2,
                const std::vector<std::vector<double>>& A) {
    const double * const * A_data = reinterpret_cast<const double * const *>(&A[0]);

    /* x1 += A * y_1  (row‑wise) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double *Ai = A_data[i];
        const double *yj = y_1.data();
        for (int j = 0; j < n; ++j)
            sum += Ai[j] * yj[j];
        x1[i] += sum;
    }

    /* x2 += Aᵀ * y_2  (column‑wise) */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double *yj = y_2.data();
        for (int j = 0; j < n; ++j)
            sum += A_data[j][i] * yj[j];
        x2[i] += sum;
    }
}
```
**Key optimisations**

1. **OpenMP parallelisation** – outer loops (`i`) are parallelised.  
2. **Pointer arithmetic** – raw pointer access (`A_data`) removes `operator[]` overhead.  
3. **Loop‑local accumulation** – use a local `sum` to minimise memory traffic.  
4. **Cache friendly access** – the first kernel accesses `A` row‑wise; the second accesses columns of `A` via pointer indirection, still efficient on modern x86‑64.  
5. **Const correctness** – `y_1`, `y_2`, and `A` are read‑only where appropriate.

