/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* The input matrices are stored as vectors of rows.
       We work directly with the underlying data pointers
       to avoid bounds checks and to get better vectorisation. */

    const double sbeta  = beta;
    const double salpha = alpha;

    /* Parallelise over the outer index i.  Each thread
       works on a distinct row of C, hence no data races. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double* Ci   = C[i].data();          // row i of C (only 0..i used)
        double* Ai   = A[i].data();          // row i of A
        // apply beta to the lower‑triangular part of C[i]
        for (int j = 0; j <= i; ++j)
            Ci[j] *= sbeta;

        /* Accumulate alpha * A[i][k] * A[j][k] for all k.
           The inner loop over j runs over the lower half of the row,
           so we cache Ai[k] once per k and then use it for all j. */
        for (int k = 0; k < m; ++k)
        {
            double aik = salpha * Ai[k];
            for (int j = 0; j <= i; ++j)
            {
                // A[j][k] is read through the row vector *A[j]
                Ci[j] += aik * A[j][k];
            }
        }
    }
}
