#include <cstddef>
#include <omp.h>

/* Optimised QR Decomposition with Modified Gram Schmidt
 * http://www.inf.ethz.ch/personal/gander/
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Ensure data is contiguous per column (row‑major in std::vector)
    // We will repeatedly access A[i][j] so we pre‑fetch pointers.
    for (int k = 0; k < n; ++k)
    {
        /* Compute the squared norm of column k of A */
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += A[i][k] * A[i][k];

        R[k][k] = std::sqrt(nrm);
        double inv_r = 1.0 / R[k][k];

        /* Q = A / R[k][k] for column k */
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q[i][k] = A[i][k] * inv_r;

        /* Orthogonalise remaining columns */
        for (int j = k + 1; j < n; ++j)
        {
            double rkj = 0.0;
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i)
                rkj += Q[i][k] * A[i][j];

            R[k][j] = rkj;

            if (rkj == 0.0) continue;          // avoid unnecessary work

            double mul = rkj;
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                A[i][j] -= Q[i][k] * mul;
        }
    }
}
