#include <algorithm>

/* Optimised syr2k kernel.  The behaviour is identical to the reference
 * implementation – all elements of the lower triangular part of C are
 * updated as 
 *
 *      C(i,j) = beta*C(i,j)
 *              + alpha*( A(j,:) * B(i,:)^T + B(j,:) * A(i,:)^T )
 *
 * for 0 <= j <= i < n, 0 <= k < m.
 *
 * The algorithm parallelises over the outermost index `i`.  The inner
 * loops are kept simple and unrolled by the compiler.  We also cache
 * `alpha` once per thread and use a private copy of `beta` to avoid
 * false sharing. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B) {
    /* Use OpenMP to parallelise over `i`.  The loop bound is small
     * enough that a static schedule is adequate. */
#pragma omp parallel for schedule(static) default(none) \
    shared(n, m, alpha, beta, C, A, B)
    for (int i = 0; i < n; ++i) {
        /* First factor the lower triangle of C by beta. */
        double ci_beta = beta;                     // cache for rereads
        for (int j = 0; j <= i; ++j) {
            C[i][j] *= ci_beta;
        }

        /* Temporary local copy of the `i`‑th rows of A and B to avoid
         * repeated indexed loads.  The compiler will likely keep these
         * in registers. */
        const double* Ai = A[i].data();
        const double* Bi = B[i].data();

        /* Main k‑loop.  We use a single alpha* multiplication and
         * combine both outer products in one update per j. */
        for (int k = 0; k < m; ++k) {
            const double aik = Ai[k];
            const double bik = Bi[k];
            double a_k = alpha * aik;
            double b_k = alpha * bik;

            /* Update lower triangular part of C. */
            for (int j = 0; j <= i; ++j) {
                C[i][j] += A[j][k] * b_k + B[j][k] * a_k;
            }
        }
    }
}
