/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    constexpr double inv5 = 0.2;   // 1/5
    const int inner = n - 2;      // number of interior rows/cols

    for (int t = 0; t < tsteps; ++t) {
        /* ----- first half of the stencil (update B from A) ----- */
#pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i <= inner; ++i) {
            double* const Ai    = A[i].data();
            double* const Ai_u  = A[i-1].data();   // up
            double* const Ai_d  = A[i+1].data();   // down
            double* const Bi    = B[i].data();     // target

            for (int j = 1; j <= inner; ++j)
                Bi[j] = inv5 * (Ai[j] + Ai[j-1] + Ai[j+1] + Ai_d[j] + Ai_u[j]);
        }

        /* ----- second half of the stencil (update A from B) ----- */
#pragma omp parallel for schedule(static) collapse(1)
        for (int i = 1; i <= inner; ++i) {
            double* const Bi    = B[i].data();
            double* const Bi_u  = B[i-1].data();   // up
            double* const Bi_d  = B[i+1].data();   // down
            double* const Ai    = A[i].data();     // target

            for (int j = 1; j <= inner; ++j)
                Ai[j] = inv5 * (Bi[j] + Bi[j-1] + Bi[j+1] + Bi_d[j] + Bi_u[j]);
        }
    }
}
