// Helper to compute a pointer to a column in a 2‑D flattened array
inline double* col_ptr(const std::vector<double>& arr, int n, int col) {
    return const_cast<double*>(arr.data()) + col * n;
}

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double invSqrtN = 1.0 / std::sqrt(static_cast<double>(n));

    /* flatten the 2‑D data for better cache locality */
    std::vector<double> flat(n * m);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat[i * m + j] = data[i][j];

    /* 1. compute means */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += flat[i * m + j];
        mean[j] = sum / n;
    }

    /* 2. compute stddev */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sumSq = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = flat[i * m + j] - mu;
            sumSq += d * d;
        }
        double sigma = std::sqrt(sumSq / n);
        stddev[j] = (sigma <= eps) ? 1.0 : sigma;
    }

    /* 3. normalize data (subtract mean, divide by stddev*sqrt(n)) */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = flat.data() + i * m;
        for (int j = 0; j < m; ++j) {
            row[j] = (row[j] - mean[j]) * invSqrtN / stddev[j];
        }
    }

    /* 4. compute correlation matrix */
    for (int i = 0; i < m; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += flat[k * m + i] * flat[k * m + j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}
