    // (assumed by harness). If not, this may segfault.
    const double* Adata = &A[0][0];
    const double* Bdata = &B[0][0];
    const double* Cdata = &C[0][0];
    double*      Ddata = &D[0][0];
    double*      tmpdata = &tmp[0][0];

    const std::size_t strideA = nk;          // A: [ni][nk]
    const std::size_t strideB = nj;          // B: [nk][nj]
    const std::size_t strideC = nl;          // C: [nj][nl]
    const std::size_t strideD = nl;          // D: [ni][nl]
    const std::size_t strideTmp = nj;        // tmp: [ni][nj]

    /* 1st phase: compute tmp = alpha * A * B  */
