    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) {
    /* The DP table is filled along diagonals.
       Each diagonal (cells with same distance j-i) can be computed independently,
       which allows straightforward parallelization with OpenMP.          */
    for (int d = 1; d < n; ++d) {                       // diagonal offset j-i
#pragma omp parallel for schedule(static)
        for (int i = 0; i < n - d; ++i) {
            int j = i + d;                           // cell to compute
            int best = 0;

            // copy from left neighbour
            if (j - 1 >= 0) best = std::max(best, table[i][j - 1]);

            // copy from upper neighbour
            if (i + 1 < n) best = std::max(best, table[i + 1][j]);

            // pair or skip loop
            if (j - 1 >= 0 && i + 1 < n) {
                int val = table[i + 1][j - 1];
                if (i < j - 1) val += match(seq[i], seq[j]); // there is a gap
                best = std::max(best, val);
            }

            // split into two subproblems
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, table[i][k] + table[k + 1][j]);
            }

            table[i][j] = best;
        }
