    for (int i = 0; i < n; ++i) {
        /* Sub‑matrix for U */ 
        for (int j = i; j < n; ++j) {
            double w = flatA[i * n + j];
            for (int k = 0; k < i; ++k)
                w -= flatA[i * n + k] * flatA[k * n + j];
            flatA[i * n + j] = w;
        }

        /* Sub‑matrix for L (unit diagonal is implicit) */
        for (int j = 0; j < i; ++j) {
            double w = flatA[i * n + j];
            for (int k = 0; k < j; ++k)
                w -= flatA[i * n + k] * flatA[k * n + j];
            flatA[i * n + j] = w / flatA[j * n + j];
