    /* ------------------------------------------------------------------
       4. Backward substitution (Ux = y).  Also serial.
       ------------------------------------------------------------------ */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
