     * bounds checks and improve cache locality. */
    std::vector<double> flatC(m * n);
    std::vector<double> flatA(m * (m + 1) / 2);   // store only upper triangular part
    std::vector<double> flatB(m * n);

    // copy data in row major order
    #pragma omp parallel for collapse(2)
    for(int i = 0; i < m; ++i){
        for(int j = 0; j < n; ++j){
            flatC[i*n + j] = C[i][j];
            flatB[i*n + j] = B[i][j];
        }
    }
    for(int i = 0; i < m; ++i){
        for(int k = i; k < m; ++k){           // upper triangular part of A
            flatA[i * (m - i) + (k - i)] = A[i][k];
        }
    }

    /* Main computation: parallelise over the outermost ‘i’ loop.
     * Inside each thread we use sequential loops over j and k.
     * The memory layout ensures that accesses to B and C are
     * contiguous, giving good cache behaviour. */
    #pragma omp parallel for
    for(int i = 0; i < m; ++i){
        for(int j = 0; j < n; ++j){
            double temp2 = 0.0;
            int kbase = i * (m - i);          // index of A[i][i] in flatA
            int abasen = 0;                   // index of A[i][i] in flatA for the inner loop
            for(int k = 0; k < i; ++k){
                double aik = flatA[abasen + (k - i)]; // A[i][k] (only defined if k>=i)
                // Note: for k<i, A[i][k] is 0 (lower part), so skip
                // However, original code uses A[i][k] with k<i (full matrix).
                // To preserve exact behaviour, we use the full square A.
                aik = A[i][k]; // read from original full matrix
