#include <omp.h>

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑compute constants once – all other values are single‑valued and
       shared across threads.  */
    const float exp_a = std::exp(-alpha);
    const float exp_2a = std::exp(-2.0 * alpha);
    const float k = 1.0f - exp_a * (1.0f - exp_a) / (1.0f + 2.0f * alpha * exp_a - exp_2a);

    const float a1 = k, a5 = k;
    const float a2 = k * exp_a * (alpha - 1.0f), a6 = a2;
    const float a3 = k * exp_a * (alpha + 1.0f), a7 = a3;
    const float a4 = -k * exp_2a, a8 = a4;

    const float b1 = std::pow(2.0, -alpha);
    const float b2 = -exp_2a;

    const float c1 = 1.0f, c2 = 1.0f;

    /* -------- 1st horizontal forward filter  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        auto &inRow  = imgIn[i];
        auto &y1Row  = y1[i];
        for (int j = 0; j < h; ++j) {
            float val = inRow[j];
            y1Row[j] = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = val;
            ym2 = ym1;
            ym1 = y1Row[j];
        }
    }

    /* -------- 1st horizontal backward filter  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        auto &inRow  = imgIn[i];
        auto &y2Row  = y2[i];
        for (int j = h - 1; j >= 0; --j) {
            y2Row[j] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = inRow[j];
            yp2 = yp1;
            yp1 = y2Row[j];
        }
    }

    /* -------- 1st vertical forward filter  */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            float val = imgOut[i][j];
            y1[i][j] = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = val;
            ym2 = ym1;
            ym1 = y1[i][j];
        }
    }

    /* -------- 1st vertical backward filter  */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            float val = imgOut[i][j];
            y2[i][j] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = y2[i][j];
        }
    }

    /* -------- Final combination  */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = c2 * (y1[i][j] + y2[i][j]);
        }
    }
}
