/*  Optimised for GCC 9+ on x86‑64, 8 threads (OpenMP).  */
#include <vector>
#include <cstdlib>
#include <cstddef>
#include <cmath>
#include <omp.h>

/*  Flattened 2‑D container: row major, size = n*n  */
struct Mat
{
    double *p;      /* pointer to contiguous data */
    std::size_t n;  /* grid dimension */

    inline double& operator()(std::size_t i, std::size_t j) noexcept {
        return p[i * n + j];
    }
    inline double  operator()(std::size_t i, std::size_t j) const noexcept {
        return p[i * n + j];
    }
};

/*  Allocate a Mat with n×n elements, initialised to zero  */
void initMat(Mat &m, std::size_t n)
{
    m.n = n;
    m.p = static_cast<double*>(std::calloc(n * n, sizeof(double)));
}

/*  Main computational kernel.  */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u_raw,
                std::vector<std::vector<double>>& v_raw,
                std::vector<std::vector<double>>& p_raw,
                std::vector<std::vector<double>>& q_raw)
{
    /*  Flatten the input matrices  */
    Mat u, v, p, q;
    initMat(u, n);
    initMat(v, n);
    initMat(p, n);
    initMat(q, n);

    /*  Copy the original data into the flattened structures  */
    for (int i=0;i<n;++i)
        for (int j=0;j<n;++j) {
            u(i,j) = u_raw[i][j];
            v(i,j) = v_raw[i][j];
            p(i,j) = p_raw[i][j];
            q(i,j) = q_raw[i][j];
        }

    /*  Derive constants once  */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 / 2.0;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 / 2.0;
    const double e   = 1.0 + mul2;
    const double f   = d;

    /*  Main time‑stepping loop  */
    for (int t = 1; t <= tsteps; ++t)
    {
        /*  First sweep, parallel over columns  */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            v(0,i) = 1.0;
            p(i,0) = 0.0;
            q(i,0) = v(0,i);

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = a * p(i,j-1) + b;
                p(i,j) = -c / denom;
                q(i,j) = (-d * u(j,i-1) + (1.0 + 2.0 * d) * u(j,i)
                          - f * u(j,i+1) - a * q(i,j-1)) / denom;
            }

            v(n-1,i) = 1.0;

            for (int j = n-2; j >= 1; --j)
                v(j,i) = p(i,j) * v(j+1,i) + q(i,j);
        }

        /*  Second sweep, parallel over rows  */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            u(i,0) = 1.0;
            p(i,0) = 0.0;
            q(i,0) = u(i,0);

            for (int j = 1; j < n-1; ++j)
            {
                const double denom = d * p(i,j-1) + e;
                p(i,j) = -f / denom;
                q(i,j) = (-a * v(i-1,j) + (1.0 + 2.0 * a) * v(i,j)
                          - c * v(i+1,j) - d * q(i,j-1)) / denom;
            }

            u(i,n-1) = 1.0;
            for (int j = n-2; j >= 1; --j)
                u(i,j) = p(i,j) * u(i,j+1) + q(i,j);
        }
    }

    /*  Copy back the results into the original vectors  */
    for (int i=0;i<n;++i)
        for (int j=0;j<n;++j) {
            u_raw[i][j] = u(i,j);
            v_raw[i][j] = v(i,j);
            p_raw[i][j] = p(i,j);
            q_raw[i][j] = q(i,j);
        }

    /*  Free allocated memory  */
    free(u.p); free(v.p); free(p.p); free(q.p);
}
